    for (let c = 0; c < 4; c++) {
      let col = [];
      for (let r = 0; r < 4; r++) {
        col.push(this.board[r][c]);
      }
      let newCol = [];
      let merged = false;
      for (let i = 3; i >= 0; i--) {
        let cell = col[i];
        if (cell !== 0) {
          if (newCol.length > 0 && !merged && newCol[newCol.length - 1] === cell) {
            newCol[newCol.length - 1] *= 2;
            this.score += newCol[newCol.length - 1];
            merged = true;
          } else {
