class Game2048 {
  constructor(board, spawnQueue) {
    // Deep copy the board to avoid aliasing
    this.board = board.map(row => [...row]);
    this.spawnQueue = spawnQueue ? [...spawnQueue] : [];
    this.score = 0;
  }

  getBoard() {
    return this.board.map(row => [...row]);
  }

  getScore() {
    return this.score;
  }

  isGameOver() {
    // Check for empty cells
    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        if (this.board[r][c] === 0) return false;
      }
    }

    // Check for adjacent equal values horizontally and vertically
    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        const current = this.board[r][c];

        // Check right neighbor
        if (c < 3 && current === this.board[r][c + 1]) return false;

        // Check bottom neighbor
        if (r < 3 && current === this.board[r + 1][c]) return false;
      }
    }

    return true;
  }

  move(dir) {
    const oldBoard = JSON.stringify(this.board);
    let moved = false;

    // Helper to slide and merge a single row (left direction logic)
    const processLine = (line) => {
      // Filter out zeros
      let tiles = line.filter(val => val !== 0);
      let merged = [];
      let skipNext = false;

      for (let i = 0; i < tiles.length; i++) {
        if (skipNext) {
          skipNext = false;
          continue;
        }

        if (i + 1 < tiles.length && tiles[i] === tiles[i + 1]) {
          merged.push(tiles[i] * 2);
          this.score += tiles[i] * 2;
          skipNext = true;
        } else {
          merged.push(tiles[i]);
        }
      }

      // Pad with zeros to length 4
      while (merged.length < 4) {
        merged.push(0);
      }
      return merged;
    };

    if (dir === "left") {
      for (let r = 0; r < 4; r++) {
        this.board[r] = processLine(this.board[r]);
      }
    } else if (dir === "right") {
      for (let r = 0; r < 4; r++) {
        const reversed = [...this.board[r]].reverse();
        this.board[r] = processLine(reversed).reverse();
      }
    } else if (dir === "up") {
      for (let c = 0; c < 4; c++) {
        let col = [this.board[0][c], this.board[1][c], this.board[2][c], this.board[3][c]];
        const processed = processLine(col);
        for (let r = 0; r < 4; r++) {
          this.board[r][c] = processed[r];
        }
      }
    } else if (dir === "down") {
      for (let c = 0; c < 4; c++) {
        let col = [this.board[0][c], this.board[1][c], this.board[2][c], this.board[3][c]];
        const reversed = [...col].reverse();
        const processed = processLine(reversed);
        const finalCol = [...processed].reverse();
        for (let r = 0; r < 4; r++) {
          this.board[r][c] = finalCol[r];
        }
      }
    }

    if (oldBoard !== JSON.stringify(this.board)) {
      moved = true;

      // Consume spawn queue if available
      if (this.spawnQueue.length > 0) {
        const spawn = this.spawnQueue.shift();
        this.board[spawn.r][spawn.c] = spawn.v;
      }
    }

    return moved;
  }
}
