```javascript
/**
 * Calculates the Levenshtein distance between two strings.
 * @param {string} a The first string.
 * @param {string} b The second string.
 * @returns {number} The minimum number of operations (insertions, deletions, or substitutions) required to change a to b.
 */
const editDistance = (a, b) => {
    const m = a.length;
    const n = b.length;

    // Create a 2D array (m+1) x (n+1) to store the distances
    const dp = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

    // Initialize the first row and column
    // dp[i][0] represents transforming a[1..i] to an empty string (i deletions)
    for (let i = 0; i <= m; i++) {
        dp[i][0] = i;
    }

    // dp[0][j] represents transforming an empty string to b[1..j] (j insertions)
    for (let j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    // Fill the DP table
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            // Cost of substitution: 0 if characters match, 1 otherwise
            const cost = (a[i - 1] === b[j - 1]) ? 0 : 1;

            // dp[i][j] is the minimum of:
            // 1. Deletion: dp[i-1][j] + 1
            // 2. Insertion: dp[i][j-1] + 1
            // 3. Substitution/Match: dp[i-1][j-1] + cost
            dp[i][j] = Math.min(
                dp[i - 1][j] + 1,        // Deletion
                dp[i][j - 1] + 1,        // Insertion
                dp[i - 1][j - 1] + cost  // Substitution or Match
            );
        }
    }

    // The result is stored in the bottom-right cell
    return dp[m][n];
};
