class Game2048 {
  constructor(board, spawnQueue) {
    this.board = board.map(row => [...row]);
    this.spawnQueue = spawnQueue;
    this.score = 0;
  }

  getBoard() {
    return this.board.map(row => [...row]);
  }

  getScore() {
    return this.score;
  }

  isGameOver() {
    const empty = this.board.some(row => row.includes(0));
    if (!empty) {
      for (let r = 0; r < 4; r++) {
        for (let c = 0; c < 4; c++) {
          if ((c < 3 && this.board[r][c] === this.board[r][c + 1]) ||
              (r < 3 && this.board[r][c] === this.board[r + 1][c])) {
            return false;
          }
        }
      }
      return true;
    }
    return false;
  }

  move(dir) {
    const changed = this._move(dir);
    if (changed) {
      const { r, c, v } = this.spawnQueue.shift();
      this.board[r][c] = v;
      this.score += v;
      return true;
    }
    return false;
  }

  _move(dir) {
    const changed = (dir === 'left' || dir === 'right');
    const reverse = dir === 'right';
    const transpose = dir === 'up' || dir === 'down';

    if (transpose) {
      for (let c = 0; c < 4; c++) {
        const col = this.board.map(row => row[c]);
        const movedCol = this._slideAndMerge(col, reverse);
        for (let r = 0; r < 4; r++) {
          this.board[r][c] = movedCol[r];
        }
      }
      if (transpose) {
        for (let r = 0; r < 4; r++) {
          for (let c = 0; c < 4; c++) {
            this.board[r][c] = this.board[c][r];
          }
        }
      }
    } else {
      const movedRow = this._slideAndMerge(this.board[r], reverse);
      this.board[r] = movedRow;
    }

    return changed;
  }

  _slideAndMerge(line, reverse) {
    const nonZero = line.filter(v => v !== 0);
    const merged = [];
    let i = 0;
    while (i < nonZero.length) {
      if (i + 1 < nonZero.length && nonZero[i] === nonZero[i + 1]) {
        merged.push(nonZero[i] * 2);
        this.score += nonZero[i] * 2;
        i += 2;
      } else {
        merged.push(nonZero[i]);
        i++;
      }
    }
    merged.push(...Array(4 - merged.length).fill(0));
    return reverse ? merged.reverse() : merged;
  }
}
